import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertThrows;

public class CalculatorTest {

    @Test
    public void testAddition() {
        Calculator calculator = new Calculator();
        assertEquals(5, calculator.add(2, 3));
        assertEquals(10, calculator.add(-2, 3));
        assertEquals(0, calculator.add(-2, -3));
    }

    @Test
    public void testSubtraction() {
        Calculator calculator = new Calculator();
        assertEquals(5, calculator.subtract(2, 3));
        assertEquals(7, calculator.subtract(-2, 3));
        assertEquals(-5, calculator.subtract(-2, -3));
    }

    @Test
    public void testMultiplication() {
        Calculator calculator = new Calculator();
        assertEquals(6, calculator.multiply(2, 3));
        assertEquals(-6, calculator.multiply(-2, 3));
        assertEquals(0, calculator.multiply(-2, -3));
    }

    @Test
    public void testDivision() {
        Calculator calculator = new Calculator();
        assertEquals(2, calculator.divide(4, 2));
        assertEquals(-2, calculator.divide(-4, 2));
        assertEquals(0, calculator.divide(0, 2));
        assertThrows(ArithmeticException.class, () -> calculator.divide(0, 2));
    }

    @Test
    public void testInvalidInput() {
        Calculator calculator = new Calculator();
        assertThrows(ArithmeticException.class, () -> calculator.add(0, 0));
        assertThrows(ArithmeticException.class, () -> calculator.subtract(0, 0));
        assertThrows(ArithmeticException.class, () -> calculator.multiply(0, 0));
        assertThrows(ArithmeticException.class, () -> calculator.divide(0, 0));
    }
}

class Calculator {
    public int add(int a, int b) {
        if (a == 0 || b == 0) {
            throw new ArithmeticException("Cannot divide by zero");
        }
        return a + b;
    }

    public int subtract(int a, int b) {
        if (a == 0 || b == 0) {
            throw new ArithmeticException("Cannot divide by zero");
        }
        return a - b;
    }

    public int multiply(int a, int b) {
        if (a == 0 || b == 0) {
            throw new ArithmeticException("Cannot divide by zero");
        }
        return a * b;
    }

    public double divide(double a, double b) {
        if (b == 0) {
            throw new ArithmeticException("Cannot divide by zero");
        }
        return a / b;
    }
}
