// Import Whatsup framework
import { Application, View, Text, Input, Button, List, Reactivity } from 'whatsup';

// Create the application
const app = new Application();

// Create a reactive list
const list = Reactivity observable([]);
const newList = list.map(item => ({ id: item.id, text: item.text }));

// Create the view
app.view = new View({
  title: 'Item List',
  content: (
    <View>
      <Text>Item List</Text>
      <List items={newList} onItemChange={(newItem) => {
        if (newItem.text) {
          list.push(newItem);
          newList = list.map(item => ({ id: item.id, text: item.text }));
        }
      }} />
      <Input
        type="text"
        placeholder="Enter item"
        onInput={(e) => {
          if (e.value) {
            list.push({ id: list.length + 1, text: e.value });
            newList = list.map(item => ({ id: item.id, text: item.text }));
            e.value = '';
          }
        }}
      />
      <Button onClick={() => list.pop()} disabled={!list.length}>
        Remove Item
      </Button>
    </View>
  ),
});

// Run the application
app.run();
