import io.tinylog.Logger;
import io.tinylog.logback.TinyLogLogbackAppender;
import io.tinylog.logback.TinyLogLogbackLayout;
import io.tinylog.TinyLog;
import io.tinylog.config.TinyLogConfig;
import io.tinylog.config.TinyLogFactory;
import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RestController;
import org.springframework.web.server.ResponseStatusException;

import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;
import java.util.logging.Level;
import java.util.logging.Logger;

@SpringBootApplication
@RestController
public class LoggingServiceApplication {

    private static final Logger logger = Logger.getLogger(LoggingServiceApplication.class.getName());

    private static final DateTimeFormatter formatter = DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm:ss");

    public static void main(String[] args) {
        TinyLogConfig config = TinyLogConfig.builder()
                .appender(new TinyLogLogbackAppender("file", "logs/logfile.log"))
                .layout(new TinyLogLogbackLayout())
                .build();
        TinyLogFactory.init(config);
        TinyLog.info("TinyLog initialized successfully");

        SpringApplication.run(LoggingServiceApplication.class, args);
    }

    @PostMapping("/log/info")
    public ResponseEntity<String> logInfo(@RequestBody String message) {
        try {
            logger.info("{} - {}", LocalDateTime.now().format(formatter), message);
            return ResponseEntity.ok("Info message logged successfully");
        } catch (Exception e) {
            logger.error("Error logging info message", e);
            throw new ResponseStatusException(HttpStatus.INTERNAL_SERVER_ERROR, "Failed to log info message");
        }
    }

    @PostMapping("/log/debug")
    public ResponseEntity<String> logDebug(@RequestBody String message) {
        try {
            logger.debug("{} - {}", LocalDateTime.now().format(formatter), message);
            return ResponseEntity.ok("Debug message logged successfully");
        } catch (Exception e) {
            logger.error("Error logging debug message", e);
            throw new ResponseStatusException(HttpStatus.INTERNAL_SERVER_ERROR, "Failed to log debug message");
        }
    }

    @PostMapping("/log/error")
    public ResponseEntity<String> logError(@RequestBody String message) {
        try {
            logger.error("{} - {}", LocalDateTime.now().format(formatter), message);
            return ResponseEntity.ok("Error message logged successfully");
        } catch (Exception e) {
            logger.error("Error logging error message", e);
            throw new ResponseStatusException(HttpStatus.INTERNAL_SERVER_ERROR, "Failed to log error message");
        }
    }
}
