#include <cpputest/TestHarness.h>
#include <cpputest/UnitTest.h>
#include <cpputest/ExtensionTest.h>

#include <iostream>
#include <stdexcept>

class Calculator {
public:
    double add(double num1, double num2) {
        return num1 + num2;
    }

    double subtract(double num1, double num2) {
        return num1 - num2;
    }

    double multiply(double num1, double num2) {
        return num1 * num2;
    }

    double divide(double num1, double num2) {
        if (num2 == 0) {
            throw std::runtime_error("Cannot divide by zero");
        }
        return num1 / num2;
    }
};

TEST_CASE("Calculator Test Suite") {
    Calculator calculator;

    SECTION("Addition") {
        SECTION("Positive numbers") {
            CHECK(calculator.add(5, 3) == 8);
            CHECK(calculator.add(10, 2) == 12);
            CHECK(calculator.add(-1, 1) == 0);
        }

        SECTION("Negative numbers") {
            CHECK(calculator.add(-5, 3) == -2);
            CHECK(calculator.add(-10, 2) == -8);
            CHECK(calculator.add(1, -1) == 0);
        }

        SECTION("Mixed numbers") {
            CHECK(calculator.add(5, -3) == 2);
            CHECK(calculator.add(-10, 2) == -8);
            CHECK(calculator.add(1, -1) == 0);
        }
    }

    SECTION("Subtraction") {
        SECTION("Positive numbers") {
            CHECK(calculator.subtract(5, 3) == 2);
            CHECK(calculator.subtract(10, 2) == 8);
            CHECK(calculator.subtract(-1, 1) == -2);
        }

        SECTION("Negative numbers") {
            CHECK(calculator.subtract(-5, 3) == -8);
            CHECK(calculator.subtract(-10, 2) == -12);
            CHECK(calculator.subtract(1, -1) == 2);
        }

        SECTION("Mixed numbers") {
            CHECK(calculator.subtract(5, -3) == 8);
            CHECK(calculator.subtract(-10, 2) == -12);
            CHECK(calculator.subtract(1, -1) == 2);
        }
    }

    SECTION("Multiplication") {
        SECTION("Positive numbers") {
            CHECK(calculator.multiply(5, 3) == 15);
            CHECK(calculator.multiply(10, 2) == 20);
            CHECK(calculator.multiply(-1, 1) == -1);
        }

        SECTION("Negative numbers") {
            CHECK(calculator.multiply(-5, 3) == -15);
            CHECK(calculator.multiply(-10, 2) == -20);
            CHECK(calculator.multiply(1, -1) == -1);
        }

        SECTION("Mixed numbers") {
            CHECK(calculator.multiply(5, -3) == -15);
            CHECK(calculator.multiply(-10, 2) == -20);
            CHECK(calculator.multiply(1, -1) == -1);
        }
    }

    SECTION("Division") {
        SECTION("Positive numbers") {
            CHECK(calculator.divide(5, 3) == 1.66667);
            CHECK(calculator.divide(10, 2) == 5);
            CHECK(calculator.divide(-1, 1) == -1);
        }

        SECTION("Negative numbers") {
            CHECK(calculator.divide(-5, 3) == -1.66667);
            CHECK(calculator.divide(-10, 2) == -5);
            CHECK(calculator.divide(1, -1) == -1);
        }

        SECTION("Mixed numbers") {
            CHECK(calculator.divide(5, -3) == -1.66667);
            CHECK(calculator.divide(-10, 2) == -5);
            CHECK(calculator.divide(1, -1) == -1);
        }

        SECTION("Division by zero") {
            EXPECT_THROW(calculator.divide(5, 0), std::runtime_error);
            EXPECT_THROW(calculator.divide(-5, 0), std::runtime_error);
            EXPECT_THROW(calculator.divide(5, -0), std::runtime_error);
        }
    }
};

int main() {
    CppUTest::init();
    CppUTest::run();
    CppUTest::clean();
    return 0;
}
