// Import necessary libraries
use bevy::prelude::*;

fn main() {
    App::new()
        .add_plugins(DefaultPlugins)
        .add_startup_system(setup.system())
        .add_system(window_event_system.system())
        .add_system(rectangle_color_system.system())
        .run();
}

fn setup(mut commands: Commands) {
    // Create a new window
    commands.spawn_window(
        WindowDescriptor {
            title: "Color Rectangle".to_string(),
            ..Default::default()
        },
        &mut query::WindowQueries::update(|mut window_query, _mut app_state| {
            window_query.resize(800, 600)
        }),
    )
    .insert(Color(0.0, 0.0, 0.0));
}

fn window_event_system(mut window: ResMut<Window>, mut keyboard: ResMut<Input<KeyCode>>, mut commands: Commands) {
    if keyboard.pressed(KeyCode::Escape) {
        commands.remove_resource(WindowState::Closed);
    }
    if window.width > 0 && window.height > 0 {
        commands.spawn_child_window(
            WindowDescriptor {
                title: "Color Rectangle".to_string(),
                ..Default::default()
            },
            &mut query::ChildWindowQueries::update(|mut child_query, _mut app_state| {
                child_query.resize(window.width, window.height)
            }),
        )
        .insert(Color(0.0, 0.0, 0.0));
    }
}

fn rectangle_color_system(mut commands: Commands, mut keyboard: ResMut<Input<KeyCode>>, mut rectangle_color: ResMut<Color>) {
    if keyboard.pressed(KeyCode::W) {
        rectangle_color.value = Color(1.0, 0.0, 0.0);
    }
    if keyboard.pressed(KeyCode::A) {
        rectangle_color.value = Color(0.0, 1.0, 0.0);
    }
    if keyboard.pressed(KeyCode::S) {
        rectangle_color.value = Color(0.0, 0.0, 1.0);
    }
    if keyboard.pressed(KeyCode::D) {
        rectangle_color.value = Color(1.0, 1.0, 0.0);
    }
    if keyboard.pressed(KeyCode::Space) {
        rectangle_color.value = Color(0.0, 0.0, 0.0);
    }
}
