const express = require('express');
const app = express();
const bodyParser = require('body-parser');
const mongoose = require('mongoose');

// Connect to MongoDB
mongoose.connect('mongodb://localhost/to-do-list', { useNewUrlParser: true, useUnifiedTopology: true });

// Define schema for Todo item
const todoSchema = new mongoose.Schema({
  title: String,
  description: String,
  completed: Boolean
});

// Create model
const Todo = mongoose.model('Todo', todoSchema);

// Middleware
app.use(bodyParser.json());
app.use(bodyParser.urlencoded({ extended: true }));
app.use(express.json());

// Input validation middleware
const validateInput = (req, res, next) => {
  if (!req.body.title || !req.body.description) {
    return res.status(400).json({ message: 'Title and description are required' });
  }
  next();
};

// Create endpoint
app.post('/todos', validateInput, (req, res) => {
  const todo = new Todo(req.body);
  todo.save((err, todo) => {
    if (err) {
      res.status(500).json({ message: 'Failed to create todo item' });
    } else {
      res.json(todo);
    }
  });
});

// Read endpoint
app.get('/todos', (req, res) => {
