        if data.name.is_empty() {
            Err(Error::BadRequest("Name is required"))
        } else {
            let items = self.get_items()?;
            items.items.push(Item { id: items.items.len() + 1, name: data.name });
            Ok(Items { items })
        }
    }
}

// Create the application
