use crate::error::Error;
use crate::models::Note;
use crate::repository::NoteRepository;
use crate::schema::notes;
use diesel::prelude::*;
use diesel::result::Error as DieselError;
use jsonwebtoken::{encode, Header, Token};
use serde::{Deserialize, Serialize};
use std::collections::HashMap;
use std::env;
use std::path::PathBuf;

#[derive(Serialize, Deserialize, Queryable, Insertable)]
struct Note {
    id: i32,
    title: String,
    content: String,
}

#[derive(Serialize, Deserialize, Queryable, Insertable)]
struct NoteRepository {
    id: i32,
    title: String,
    content: String,
}

const DATABASE_URL: &str = env::var("DATABASE_URL").unwrap();

#[tokio::main]
async fn main() -> Result<(), Error> {
    let connection = establish_connection().await?;
    let schema = notes::table;

    let repository = NoteRepository::table
        .establish_connection(&connection)
        .unwrap()
        .load::<NoteRepository>(&schema)
        .await?;

    let api_key = env::var("API_KEY")?;
    let secret_key = env::var("SECRET_KEY")?;

    let header = Header::new(HeaderAlgorithm::HS256, secret_key.as_bytes());
    let claims = HashMap::from([("exp", 1000)]);
    let payload = encode(&header, &claims, None).unwrap();
    let token = format!("Bearer {}", payload);

    let routes = web::scope("/notes")
        .route("/create", web::post().to(create_note))
        .route("/read", web::get().to(read_notes))
        .route("/update", web::put().to(update_note))
        .route("/delete", web::delete().to(delete_note))
        .route("/token", web::post().to(get_token));

    web::server(routes)
        .bind("127.0.0.1:8080")?
        .run()
        .await
}

async fn create_note(req: web::Json<CreateNote>) -> Result<web::Json<Note>, Error> {
    let note = Note {
        title: req.title,
        content: req.content,
    };

    diesel::insert_into(Note::table)
        .values(&note)
        .execute(&establish_connection().await?)
        .map_err(|e| Error::Database(e))?;

    Ok(web::Json(note))
}

async fn read_notes(req: web::Json<ReadNotes>) -> Result<web::Json<Vec<Note>>, Error> {
    let notes = Note::table
        .establish_connection(&establish_connection().await?)
        .load::<Note>(&establish_connection().await?)
        .map_err(|e| Error::Database(e))?;

    Ok(web::Json(notes))
}

async fn update_note(req: web::Json<UpdateNote>) -> Result<web::Json<Note>, Error> {
    let note = Note::table
        .find(req.id)
        .establish_connection(&establish_connection().await?)
        .load::<Note>(&establish_connection().await?)
        .map_err(|e| Error::Database(e))?;

    if req.title != note.title {
        note.title = req.title;
    }
    if req.content != note.content {
        note.content = req.content;
    }

    diesel::update(Note::table)
        .filter(Note::id.eq(req.id))
        .set(Note::title.eq(req.title))
        .set(Note::content.eq(req.content))
        .execute(&establish_connection().await?)
        .map_err(|e| Error::Database(e))?;

    Ok(web::Json(note))
}

async fn delete_note(req: web::Json<DeleteNote>) -> Result<web::Json<()>, Error> {
    diesel::delete(Note::table.find(req.id))
        .execute(&establish_connection().await?)
        .map_err(|e| Error::Database(e))?;

    Ok(web::Json(()))
}

async fn get_token(req: web::Json<GetToken>) -> Result<web::Json<String>, Error> {
    if req.api_key != env::var("API_KEY")? {
        return Err(Error::InvalidApiKey);
    }

    let claims = HashMap::from([("exp", 1000)]);
    let payload = encode(&Header::new(HeaderAlgorithm::HS256, env::var("SECRET_KEY")?), &claims, None).unwrap();
    let token = format!("Bearer {}", payload);

    Ok(web::Json(token))
}

fn establish_connection() -> Result<PgConnection, DieselError> {
    let database_url = DATABASE_URL.clone();
    let manager = Pool::new(&database_url, 1, std::time::Duration::from_secs(10))
        .expect("Error creating pool");

    manager.get().await.expect("Error getting connection").unwrap()
}
