class Book(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    title = db.Column(db.String(100), nullable=False)
    author = db.Column(db.String(100), nullable=False)
    publication_date = db.Column(db.DateTime, nullable=False)

class BookSchema(ma.SQLAlchemyAutoSchema):
    class Meta:
        model = Book

@app.route('/books', methods=['POST'])
def create_book():
    try:
        data = request.get_json()
        book_schema = BookSchema().load(data)
        new_book = Book(title=book_schema.title, author=book_schema.author, publication_date=book_schema.publication_date)
        db.session.add(new_book)
        db.session.commit()
        return jsonify(book_schema.dump(new_book)), 201
    except Exception as e:
        logging.error(str(e))
        return jsonify({'message': 'Failed to create book'}), 400

@app.route('/books', methods=['GET'])
def get_books():
    books = Book.query.all()
    return jsonify([BookSchema().dump(book) for book in books])

@app.route('/books/<id>', methods=['GET'])
def get_book(id):
    book = Book.query.get(id)
    if book is None:
        return jsonify({'message': 'Book not found'}), 404
    return jsonify(BookSchema().dump(book))

@app.route('/books/<id>', methods=['PUT'])
def update_book(id):
    try:
        book = Book.query.get(id)
        if book is None:
            return jsonify({'message': 'Book not found'}), 404
        data = request.get_json()
        book_schema = BookSchema().load(data)
        book.title = book_schema.title
        book.author = book_schema.author
        book.publication_date = book_schema.publication_date
        db.session.commit()
        return jsonify(book_schema.dump(book))
    except Exception as e:
        logging.error(str(e))
        return jsonify({'message': 'Failed to update book'}), 400

@app.route('/books/<id>', methods=['DELETE'])
def delete_book(id):
    try:
        book = Book.query.get(id)
        if book is None:
            return jsonify({'message': 'Book not found'}), 404
        db.session.delete(book)
        db.session.commit()
        return jsonify({'message': 'Book deleted'})
    except Exception as e:
        logging.error(str(e))
        return jsonify({'message': 'Failed to delete book'}), 400

if __name__ == '__main__':
    db.create_all()
