import { BrowserRouter, Route, Switch } from 'react-router-dom';
import axios from 'axios';

// Create the Whatsup application
const app = new Whatsup({
  title: 'User List App',
  version: '1.0.0',
  entry: './index.html',
});

// Create the history object
const history = createWebHistory();

// Define the UserList component
const UserList = () => {
  // State variables
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  // Effect hook to fetch users data when the component mounts
  useEffect(() => {
    const fetchUsers = async () => {
      setLoading(true);
      try {
        const response = await axios.get('https://jsonplaceholder.typicode.com/users');
        setUsers(response.data);
      } catch (error) {
        setError(error.message);
      } finally {
        setLoading(false);
      }
    };
    fetchUsers();
  }, []);

  // Render the component
  return (
    <div>
      {loading ? (
        <div>Loading...</div>
      ) : error ? (
        <div>Error: {error}</div>
      ) : (
        <ul>
          {users.map((user) => (
            <li key={user.id}>{user.name}</li>
          ))}
        </ul>
      )}
    </div>
  );
};

// Define the App component
const App = () => {
  return (
    <BrowserRouter>
      <Switch>
        <Route path="/" exact component={UserList} />
      </Switch>
    </BrowserRouter>
  );
};

// Render the Whatsup application
app.render(<App />, document.getElementById('root'));
