#include <iostream>
#include <vector>
#include <map>
#include <string>
#include <stdexcept>

// Define a Task class to represent a task in the DAG
class Task {
public:
    std::string name;
    std::vector<Task*> dependencies;

    Task(const std::string& name) : name(name) {}
};

// Define a DAG class to represent the directed acyclic graph
class DAG {
public:
    std::map<std::string, Task*> tasks;

    void addTask(const std::string& name) {
        if (tasks.find(name) != tasks.end()) {
            throw std::runtime_error("Task already exists in the DAG");
        }
        tasks[name] = new Task(name);
    }

    void addDependency(const std::string& taskName, const std::string& dependencyName) {
        if (tasks.find(taskName) == tasks.end() || tasks.find(dependencyName) == tasks.end()) {
            throw std::runtime_error("Task or dependency not found in the DAG");
        }
        tasks[taskName]->dependencies.push_back(tasks[dependencyName]);
    }

    void executeGPipeline() {
        std::vector<Task*> visited;
        std::vector<Task*> sortedTasks;

        // Perform topological sorting
        for (const auto& task : tasks) {
            if (visited.find(task.second) == visited.end()) {
                visitTask(task.second, visited, sortedTasks);
            }
        }

        // Execute the tasks in the sorted order
        for (const auto& task : sortedTasks) {
            std::cout << "Executing task: " << task->name << std::endl;
            // Replace this with the actual task execution logic
            std::cout << "Task executed successfully" << std::endl;
        }
    }

    void visitTask(Task* task, std::vector<Task*>& visited, std::vector<Task*>& sortedTasks) {
        visited.push_back(task);
        for (const auto& dependency : task->dependencies) {
            if (visited.find(dependency) == visited.end()) {
                visitTask(dependency, visited, sortedTasks);
            }
        }
        sortedTasks.push_back(task);
    }
};

int main() {
    DAG dag;

    // Add tasks to the DAG
    dag.addTask("Task A");
    dag.addTask("Task B");
    dag.addTask("Task C");

    // Define dependencies between tasks
    dag.addDependency("Task B", "Task A");
    dag.addDependency("Task C", "Task B");

    try {
        dag.executeGPipeline();
    } catch (const std::exception& e) {
        std::cerr << "Error: " << e.what() << std::endl;
        return 1;
    }

    return 0;
}
