        parser.add_argument('-a', '--add', dest='add', action='store_true', help='Perform addition')
        parser.add_argument('-s', '--subtract', dest='subtract', action='store_true', help='Perform subtraction')
        parser.add_argument('-m', '--multiply', dest='multiply', action='store_true', help='Perform multiplication')
        parser.add_argument('-d', '--divide', dest='divide', action='store_true', help='Perform division')
        parser.add_argument('-n', '--number1', type=float, dest='number1', help='First number')
        parser.add_argument('-b', '--number2', type=float, dest='number2', help='Second number')
        return parser.parse_args()

    def run(self):
        if self.args.number1 is None or self.args.number2 is None:
            self.fail('Please provide both numbers')

        if self.args.add and self.args.subtract and self.args.multiply and self.args.divide:
            self.fail('Please choose one operation')

        if self.args.add:
            result = self.args.number1 + self.args.number2
            self.stdout.write('Result: %s\n' % result)
        elif self.args.subtract:
            result = self.args.number1 - self.args.number2
            self.stdout.write('Result: %s\n' % result)
        elif self.args.multiply:
            result = self.args.number1 * self.args.number2
            self.stdout.write('Result: %s\n' % result)
        elif self.args.divide:
            if self.args.number2 == 0:
                self.fail('Cannot divide by zero')
            result = self.args.number1 / self.args.number2
            self.stdout.write('Result: %s\n' % result)
        else:
            self.fail('Please choose an operation')

