from cornice import Service
from cornice.validators import validate
from cornice.request import Request
from cornice.response import Response
from cornice.response import json
from cornice.util import json
from cornice.exceptions import HTTPNotFound
from cornice.exceptions import HTTPConflict
from cornice.exceptions import HTTPBadRequest
from cornice.exceptions import HTTPUnauthorized
from cornice.exceptions import HTTPForbidden
from cornice.exceptions import HTTPInternalServerError
from cornice import routes
from cornice import config
import logging
import datetime
import json

# Set up logging
logging.basicConfig(level=logging.INFO, format='%(asctime)s [%(levelname)s] %(message)s')

# Define the Book model
class Book:
    def __init__(self, title, author, publication_date):
        self.title = title
        self.author = author
        self.publication_date = publication_date

    @classmethod
    def from_dict(cls, data):
        return cls(data['title'], data['author'], data['publication_date'])

# Define the Book service
class BookService(Service):
    def initialize(self):
        self.books = []

    def create(self, request):
        try:
            title = request.json['title']
            author = request.json['author']
            publication_date = request.json['publication_date']
        except KeyError as e:
            raise HTTPBadRequest("Missing required fields")

        book = Book(title, author, publication_date)
        self.books.append(book)
        return Response(json={"message": "Book created successfully"})

    def read(self, request):
        book_id = request.path.split('/')[-1]
        try:
            book = next((b for b in self.books if b.title == book_id), None)
            if book is None:
                raise HTTPNotFound("Book not found")
            return Response(json={"title": book.title, "author": book.author, "publication_date": book.publication_date})
        except Exception as e:
            logging.error(f"Error reading book: {e}")
            raise HTTPInternalServerError("Internal server error")

    def update(self, request):
        try:
            book_id = request.path.split('/')[-1]
            book = next((b for b in self.books if b.title == book_id), None)
            if book is None:
                raise HTTPNotFound("Book not found")
            try:
                title = request.json['title']
                author = request.json['author']
                publication_date = request.json['publication_date']
            except KeyError as e:
                raise HTTPBadRequest("Missing required fields")
            book.title = title
            book.author = author
            book.publication_date = publication_date
            return Response(json={"message": "Book updated successfully"})
        except Exception as e:
            logging.error(f"Error updating book: {e}")
            raise HTTPInternalServerError("Internal server error")

    def delete(self, request):
        book_id = request.path.split('/')[-1]
        try:
            book = next((b for b in self.books if b.title == book_id), None)
            if book is None:
                raise HTTPNotFound("Book not found")
            self.books.remove(book)
            return Response(json={"message": "Book deleted successfully"})
        except Exception as e:
            logging.error(f"Error deleting book: {e}")
            raise HTTPInternalServerError("Internal server error")

# Define the routes
routes = [
    {'name': 'books', 'path': '/books', 'method': 'GET', 'handler': BookService.read},
    {'name': 'book', 'path': '/books/{title}', 'method': 'GET', 'handler': BookService.read},
    {'name': 'create', 'path': '/books', 'method': 'POST', 'handler': BookService.create},
    {'name': 'update', 'path': '/books/{title}', 'method': 'PUT', 'handler': BookService.update},
    {'name': 'delete', 'path': '/books/{title}', 'method': 'DELETE', 'handler': BookService.delete}
]

# Create the service
service = BookService()

# Register the routes
config.register_routes(routes)

# Run the service
config.run()
