import org.tinylog.exceptions.LogException;

import com.opencsv.CSVReader;
import com.opencsv.CSVReaderBuilder;

public class UserRegistrationApp {

    public static void main(String[] args) {
        String csvFilePath = "user_registration_records.csv";
        String logFilePath = "user_registration_logs.log";

        Properties logProperties = new Properties();
        logProperties.put("format", "yyyy-MM-dd HH:mm:ss");
        logProperties.put("date_format", "yyyy-MM-dd");
        logProperties.put("date_pattern", "yyyy-MM-dd HH:mm:ss");

        Log.init(logProperties);

        try (BufferedReader br = new BufferedReader(new FileReader(csvFilePath));
             BufferedWriter bw = new BufferedWriter(new FileWriter(logFilePath))) {

            try (CSVReader csvReader = new CSVReaderBuilder(br).build()) {
                String[] nextLine;
                while ((nextLine = csvReader.readNext()) != null) {
                    if (nextLine.length < 3) {
                        Log.error("Invalid user registration record: missing name or email");
                        continue;
                    }

                    String name = nextLine[0];
                    String email = nextLine[1];

                    if (name == null || name.isEmpty() || email == null || email.isEmpty()) {
                        Log.error("Invalid user registration record: missing required field");
                        continue;
                    }

                    try {
                        // Simulating registration process
                        Log.info("User {} registered successfully at {}", name, new SimpleDateFormat("yyyy-MM-dd HH:mm:ss").format(new Date()));
                    } catch (Exception e) {
                        Log.error("User {} registration failed with error: {}", name, e.getMessage());
                    }
                }
            }
        } catch (IOException e) {
            Log.error("Error reading CSV file: {}", e.getMessage());
        } catch (LogException e) {
            Log.error("Error initializing Tinylog: {}", e.getMessage());
        }
    }
}
