use bevy::prelude::*;

fn main() {
    App::new()
        .add_plugins(DefaultPlugins)
        .add_plugin(RoguePlugs)
        .add_startup_system(startup_system)
        .add_system(move_player_system)
        .add_system(check_collision_system)
        .add_system(update_health_system)
        .add_system(game_over_system)
        .add_system(start_game_system)
        .run();
}

// Start system
fn startup_system(mut commands: Commands) {
    commands
        .spawn(Portal::new(StartScreen))
        .insert(StartScreen);
}

// Move player system
fn move_player_system(
    mut keyboard_input: ResMut<KeyboardInput>,
    mut player: Query<(&mut Position, &mut Velocity)>,
) {
    let mut player_entity = player.iter_mut().next().unwrap().0;
    if let Some(input) = keyboard_input.get_input() {
        match input {
            Input::W => player.y += 1.0,
            Input::A => player.x -= 1.0,
            Input::S => player.y -= 1.0,
            Input::D => player.x += 1.0,
            _ => (),
        }
    }
}

// Check collision system
fn check_collision_system(
    mut commands: Commands,
    mut player: Query<(&mut Position, &mut Velocity)>,
    static_obstacles: Query<(&Position, &Size)>,
) {
    let mut player_entity = player.iter_mut().next().unwrap().0;
    for (obstacle_entity, _) in static_obstacles.iter() {
        if player_entity.x < obstacle_entity.x + 1.0
            && player_entity.x + 1.0 > obstacle_entity.x
            && player_entity.y < obstacle_entity.y + 1.0
            && player_entity.y + 1.0 > obstacle_entity.y
        {
            commands.entity(player_entity).insert(Collided);
            commands.entity(obstacle_entity).insert(Collided);
        }
    }
}

// Update health system
fn update_health_system(mut player: Query<(&mut Health, &mut Position)>) {
    for (mut health, _) in player.iter_mut() {
        if health.value > 0.0 {
            health.value -= 1.0;
        } else {
            // Game over
            commands.entity(player.iter().next().unwrap().0).insert(GameOver);
        }
    }
}

// Game over system
fn game_over_system(mut commands: Commands, mut player: Query<(&mut Position, &mut Health)>) {
    for (position, _) in player.iter_mut() {
        commands.entity(position).insert(GameOver);
    }
}

// Start game system
fn start_game_system(mut commands: Commands) {
    commands.spawn(Portal::new(GameScreen))
        .insert(GameScreen);
}

// RoguePlugs
mod rogue_plugs {
    use bevy::prelude::*;

    pub struct RoguePlugs;

    impl Plugin for RoguePlugs {
        fn build(&self, app: &mut App) {
            app.add_system_set(SystemSet::on_enter(GameScreen::is_entered).with_system(move_player_system));
            app.add_system_set(SystemSet::on_exit(GameScreen::is_entered).with_system(check_collision_system));
            app.add_system_set(SystemSet::on_exit(GameScreen::is_entered).with_system(update_health_system));
        }
    }

    #[derive(Component, Debug)]
    pub struct StartScreen {}

    #[derive(Component, Debug)]
    pub struct GameOver {}

    #[derive(Component, Debug)]
    pub struct Collided {}

    #[derive(Component, Debug)]
    pub struct Portal<T>(pub T);

    #[derive(Component, Debug)]
    pub struct KeyboardInput;

    #[derive(Component, Debug)]
    pub struct Position;

    #[derive(Component, Debug)]
    pub struct Velocity;

    #[derive(Component, Debug)]
    pub struct Health(f32);

    #[derive(Component, Debug)]
    pub struct Size(f32, f32);

    #[derive(Component, Debug)]
    pub enum GameScreen {
        Started,
        Game,
        GameOver,
    }
}
