#include <iostream>
#include <fstream>
#include <vector>
#include <string>
#include <chrono>
#include <thread>
#include <json/json.h>

#include <CGraph/CGraph.h>
#include <CGraph/CGraphUtils.h>

class ImageLoader : public CGraph::Node {
public:
    ImageLoader(std::string directory) : directory_(directory) {}

    void process() {
        auto start_time = std::chrono::high_resolution_clock::now();
        std::vector<std::string> files;
        for (const auto& entry : CGraph::FileSystem::listDirectory(directory_)) {
            if (entry.isFile()) {
                files.push_back(entry.path().string());
            }
        }
        for (const auto& file : files) {
            auto image = CGraph::Image::load(file);
            emit_signal("input", image);
        }
        auto end_time = std::chrono::high_resolution_clock::now();
        auto execution_time = std::chrono::duration_cast<std::chrono::milliseconds>(end_time - start_time).count();
        emit_signal("execution_time", execution_time);
    }

private:
    std::string directory_;
};

class ImageFilter : public CGraph::Node {
public:
    ImageFilter() {}

    void process(CGraph::Image image) {
        auto start_time = std::chrono::high_resolution_clock::now();
        auto filtered_image = CGraph::Image::convertToGrayscale(image);
        emit_signal("output", filtered_image);
        auto end_time = std::chrono::high_resolution_clock::now();
        auto execution_time = std::chrono::duration_cast<std::chrono::milliseconds>(end_time - start_time).count();
        emit_signal("execution_time", execution_time);
    }
};

class ImageSaver : public CGraph::Node {
public:
    ImageSaver(std::string filename) : filename_(filename) {}

    void process(CGraph::Image image) {
        auto start_time = std::chrono::high_resolution_clock::now();
        image.save(filename_);
        auto end_time = std::chrono::high_resolution_clock::now();
        auto execution_time = std::chrono::duration_cast<std::chrono::milliseconds>(end_time - start_time).count();
        emit_signal("execution_time", execution_time);
    }

private:
    std::string filename_;
};

int main() {
    CGraph::Graph graph;
    graph.add_node("ImageLoader", ImageLoader("/path/to/images"));
    graph.add_node("ImageFilter", ImageFilter());
    graph.add_node("ImageSaver", ImageSaver("/path/to/output.png"));

    graph.add_edge("ImageLoader", "ImageFilter", "input");
    graph.add_edge("ImageFilter", "ImageSaver", "output");

    CGraph::Pipeline pipeline;
    pipeline.add_node(graph.get_node("ImageLoader"));
    pipeline.add_node(graph.get_node("ImageFilter"));
    pipeline.add_node(graph.get_node("ImageSaver"));

    pipeline.set_execution_order("ImageLoader", "ImageFilter", "ImageSaver");
    pipeline.set_dependency("ImageLoader", "ImageFilter");
    pipeline.set_dependency("ImageFilter", "ImageSaver");

    pipeline.add_dependency("ImageLoader", "ImageSaver");

    pipeline.set_measure_execution_time(true);

    pipeline.start();

    Json::Value stats;
    stats["images_processed"] = pipeline.get_node("ImageLoader").get_signal("execution_time").asInt();
    stats["images_saved"] = pipeline.get_node("ImageSaver").get_signal("execution_time").asInt();

    std::ofstream json_file("stats.json");
    json_file << stats.toStyledString();
    json_file.close();

    return 0;
}
