        Counter counter = Counter.build().name("product_stock_update_count").help("Number of product stock updates").start();
        Gauge gauge = Gauge.build().name("product_stock_update_average").help("Average product stock").start();

        // Create a histogram
        Histogram histogram = Histogram.build().name("product_stock_update_duration").help("Duration of product stock updates").start();

        // Make a request
        ProductRequest request = new ProductRequest("Product A", 10);
        service.productStockUpdate(request);

        // Increment the counter and gauge
        counter.inc();
        gauge.set(10.0);

        // Start the histogram
        histogram.startTimer();

        // Wait for the histogram to finish
        try {
            TimeUnit.SECONDS.sleep(1);
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
        }
        histogram.stopTimer();

        // Print the result
        System.out.println("Received product stock update: " + request.getStock());

        // Create a counter and gauge
        Counter counter2 = Counter.build().name("low_stock_alert_count").help("Number of low stock alerts").start();
