        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
        }
        histogram.stopTimer();

        // Print the result
        System.out.println("Received low stock alert: " + LowStockAlert.newBuilder().setProduct("Product A").setQuantity(5).build().getProduct());

        // Create a counter and gauge
        Counter counter3 = Counter.build().name("get_health_count").help("Number of get health requests").start();
        Gauge gauge3 = Gauge.build().name("get_health_average").help("Average get health requests").start();

        // Make a request
        service.getHealth();

        // Increment the counter and gauge
        counter3.inc();
        gauge3.set(10.0);

        // Start the histogram
        histogram.startTimer();

        // Wait for the histogram to finish
        try {
            TimeUnit.SECONDS.sleep(1);
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
        }
        histogram.stopTimer();

        // Print the result
        System.out.println("Received health status: " + service.getHealth().get());
    }
