// whatsup.js
import React, { useState, useEffect, useCallback } from 'react';
import WebSocket from 'ws';

// Custom hook for tracking user engagement metrics
const useEngagementTracker = () => {
  const [likes, setLikes] = useState(0);
  const [comments, setComments] = useState(0);

  const trackEngagement = useCallback((newLikes, newComments) => {
    setLikes(newLikes);
    setComments(newComments);
  }, []);

  return [likes, comments, trackEngagement];
};

// Post component
const Post = ({ post, onLike, onComment }) => {
  const [likes, setLikes, trackEngagement] = useEngagementTracker();
  const [commentCount, setCommentCount, trackEngagement] = useEngagementTracker();

  const handleLike = () => {
    onLike(post.id);
    trackEngagement(likes + 1, commentCount);
  };

  const handleComment = () => {
    onComment(post.id);
    trackEngagement(likes, commentCount + 1);
  };

  return (
    <div>
      <h2>{post.title}</h2>
      <p>{post.content}</p>
      <p>likes: {likes}</p>
      <button onClick={handleLike}>Like</button>
      <button onClick={handleComment}>Comment</button>
      <p>Comments: {commentCount}</p>
    </div>
  );
};

// CommentSection component
const CommentSection = ({ comments }) => {
  return (
    <div>
      {comments.map((comment) => (
        <p key={comment.id}>{comment.content}</p>
      ))}
    </div>
  );
};

// Feed component
const Feed = ({ posts, onLike, onComment }) => {
  const [ws, setWs] = useState(null);
  const [postsWithLazyLoading, setPostsWithLazyLoading] = useState([]);
  const [error, setError] = useState(null);

  useEffect(() => {
    const ws = new WebSocket('ws://localhost:8080');
    setWs(ws);

    ws.onmessage = (event) => {
      if (event.data.type === 'posts') {
        const posts = JSON.parse(event.data.data);
        setPostsWithLazyLoading(posts);
      }
    };

    ws.onerror = (event) => {
      setError(event);
    };

    ws.onclose = () => {
      setWs(null);
    };
  }, []);

  const handleLike = (postId) => {
    onLike(postId);
  };

  const handleComment = (postId) => {
    onComment(postId);
  };

  const handleLoadMore = useCallback(() => {
    ws.send(JSON.stringify({ type: 'loadMore' }));
  }, [ws]);

  return (
    <div>
      {error ? (
        <p>Error: {error.message}</p>
      ) : (
        <div>
          {postsWithLazyLoading.map((post) => (
            <Post key={post.id} post={post} onLike={handleLike} onComment={handleComment} />
          ))}
          <button onClick={handleLoadMore}>Load More</button>
        </div>
      )}
      <CommentSection comments={postsWithLazyLoading} />
    </div>
  );
};

export default Feed;
