from cement.ext.compression import Compression
import yaml
import logging
import smtplib
from email.mime.multipart import MIMEMultipart
from email.mime.text import MIMEText
import os
import psutil
import time
import schedule
import threading

class SystemBackupApp(App):
    def main(self):
        self.parser.add_option('--config', dest='config', help='Path to configuration file')
        self.parser.add_option('--backup-dir', dest='backup_dir', help='Path to backup directory')
        self.parser.add_option('--email', dest='email', help='Email address for notifications')
        self.parser.add_option('--password', dest='password', help='Email password for notifications')
        self.parser.add_option('--backup-schedule', dest='backup_schedule', help='Backup schedule (daily/weekly)')
        self.parser.add_option('--compression-algorithm', dest='compression_algorithm', help='Compression algorithm (zip/gzip)')
        self.parser.add_option('--audit-log', dest='audit_log', help='Path to audit log file')
        self.parser.add_argument('--config-yaml', dest='config_yaml', action='store_true', help='Use YAML configuration file')

        self.options, self.args = self.parser.parse_args()

        self.config = conf.init(self.options.config, self.options.config_yaml)
        self.backup_dir = self.options.backup_dir
        self.email = self.options.email
        self.password = self.options.password
        self.backup_schedule = self.options.backup_schedule
        self.compression_algorithm = self.options.compression_algorithm
        self.audit_log = self.options.audit_log

        self.add_subpackage('config')
        self.add_subpackage('backup')
        self.add_subpackage('report')
        self.add_subpackage('mail')
        self.add_subpackage('audit')

        self.configured = False

    def config(self, app):
        if not self.configured:
            if self.options.config_yaml:
                with open(self.options.config, 'r') as f:
                    self.config = yaml.safe_load(f)
            else:
                self.config = conf.init(self.options.config)
            self.configured = True

    def backup(self, app):
        if self.options.backup_schedule == 'daily':
            schedule.every(1).days.do(self.backup_daily)
        elif self.options.backup_schedule == 'weekly':
            schedule.every(7).days.do(self.backup_weekly)

    def backup_daily(self):
        if self.backup_dir and os.path.exists(self.backup_dir):
            for file in os.listdir(self.backup_dir):
                try:
                    os.remove(os.path.join(self.backup_dir, file))
                except Exception as e:
                    log.error(str(e))
            for file in os.listdir():
                if file.startswith('backup_'):
                    try:
                        shutil.copy(file, self.backup_dir)
                    except Exception as e:
                        log.error(str(e))
            self.send_notification('Daily backup completed')
        else:
            log.error('Backup directory does not exist')

    def backup_weekly(self):
        if self.backup_dir and os.path.exists(self.backup_dir):
            for file in os.listdir(self.backup_dir):
                try:
                    os.remove(os.path.join(self.backup_dir, file))
                except Exception as e:
                    log.error(str(e))
            for file in os.listdir():
                if file.startswith('backup_'):
                    try:
                        shutil.copy(file, self.backup_dir)
                    except Exception as e:
                        log.error(str(e))
            self.send_notification('Weekly backup completed')
        else:
            log.error('Backup directory does not exist')

    def report(self, app):
        if self.backup_dir and os.path.exists(self.backup_dir):
            for file in os.listdir(self.backup_dir):
                try:
                    os.remove(os.path.join(self.backup_dir, file))
                except Exception as e:
                    log.error(str(e))
            for file in os.listdir():
                if file.startswith('backup_'):
                    try:
                        shutil.copy(file, self.backup_dir)
                    except Exception as e:
                        log.error(str(e))
            self.send_notification('Report generated')
        else:
            log.error('Backup directory does not exist')

    def mail(self, app):
        if self.email and self.password:
            msg = MIMEMultipart()
            msg['From'] = self.email
            msg['To'] = self.email
            msg['Subject'] = 'Backup Notification'
            body = 'Backup completed successfully'
            msg.attach(MIMEText(body, 'plain'))
            server = smtplib.SMTP('smtp.gmail.com', 587)
            server.starttls()
            server.login(self.email, self.password)
            text = msg.as_string()
            server.sendmail(self.email, self.email, text)
            server.quit()
            self.send_notification('Email notification sent')
        else:
            log.error('Email address or password does not exist')

    def audit(self, app):
        if self.audit_log:
            with open(self.audit_log, 'a') as f:
                f.write('Audit log generated\n')

    def send_notification(self, message):
        if self.email and self.password:
            msg = MIMEMultipart()
            msg['From'] = self.email
            msg['To'] = self.email
            msg['Subject'] = 'Backup Notification'
            body = message
            msg.attach(MIMEText(body, 'plain'))
            server = smtplib.SMTP('smtp.gmail.com', 587)
            server.starttls()
            server.login(self.email, self.password)
            text = msg.as_string()
            server.sendmail(self.email, self.email, text)
            server.quit()
        else:
            log.error('Email address or password does not exist')

    def audit_log(self, app):
        if self.audit_log:
            with open(self.audit_log, 'a') as f:
                f.write('Audit log generated\n')

    def backup_scheduled(self):
        schedule.run_pending()
        time.sleep(1)

    def run(self):
        self.backup_scheduled()
        self.app.run()

if __name__ == '__main__':
    SystemBackupApp().main()
