// Sensor interface
class Sensor {
public:
    virtual ~Sensor() {}
    virtual void setHardwareInterface(std::shared_ptr<HardwareInterface> interface) = 0;
    virtual void validateData(const std::string& data) = 0;
    virtual void calculateChecksum(const std::string& data) = 0;
};

// Hardware interface
class HardwareInterface {
public:
    virtual ~HardwareInterface() {}
    virtual void sendData(const std::string& data) = 0;
};

// Sensor implementation
class SensorImpl : public Sensor {
private:
    std::shared_ptr<HardwareInterface> interface;
    std::string checksum;

public:
    void setHardwareInterface(std::shared_ptr<HardwareInterface> interface) override {
        this->interface = interface;
    }

    void validateData(const std::string& data) override {
        // Boundary checks
        if (data.empty() || data.length() > 100) {
            throw std::invalid_argument("Invalid data length");
        }
        // Data format validation
        if (!std::all_of(data.begin(), data.end(), [](char c) { return std::isalnum(c); })) {
            throw std::invalid_argument("Invalid data format");
        }
    }

    void calculateChecksum(const std::string& data) override {
        checksum = std::string(data);
    }
};

// Test setup/teardown
TEST_GROUP(SensorTest) {
    std::shared_ptr<HardwareInterface> interface;
    SensorImpl sensor;

public:
    void setUp() {
        interface = std::make_shared<MockHardwareInterface>();
        sensor.setHardwareInterface(interface);
    }

    void tearDown() {
        interface.reset();
    }
};

