// Import necessary libraries
import Vue from 'vue';
import VueRouter from 'vue-router';
import Vuetify from 'vuetify';
import 'vuetify/styles.css';

// Define task data model
class Task {
  constructor(id, title, status) {
    this.id = id;
    this.title = title;
    this.status = status;
  }
}

// Define Vue components
class TaskList extends Vue {
  data() {
    return {
      tasks: [
        new Task(1, 'Task 1', 'To Do'),
        new Task(2, 'Task 2', 'In Progress'),
        new Task(3, 'Task 3', 'Done'),
      ],
      filterStatus: 'To Do',
    };
  }

  methods: {
    addTask() {
      this.tasks.push(new Task(this.tasks.length + 1, 'New Task', this.filterStatus));
    },
    editTask(id, title) {
      const taskIndex = this.tasks.findIndex((task) => task.id === id);
      if (taskIndex !== -1) {
        this.tasks[taskIndex].title = title;
      }
    },
    deleteTask(id) {
      const taskIndex = this.tasks.findIndex((task) => task.id === id);
      if (taskIndex !== -1) {
        this.tasks.splice(taskIndex, 1);
      }
    },
  },
}

class TaskForm extends Vue {
  data() {
    return {
      title: '',
      status: 'To Do',
    };
  }

  methods: {
    saveTask() {
      const newTask = new Task(this.tasks.length + 1, this.title, this.status);
      this.tasks.push(newTask);
      this.title = '';
    },
  },
}

class TaskFilter extends Vue {
  data() {
    return {
      filterStatus: 'To Do',
    };
  }

  methods: {
    toggleFilterStatus(status) {
      this.filterStatus = status;
    },
  },
}

// Define Vue router
const router = new VueRouter({
  routes: [
    {
      path: '/',
      component: TaskList,
    },
    {
      path: '/tasks',
      component: TaskList,
    },
    {
      path: '/task-form',
      component: TaskForm,
    },
    {
      path: '/filter/:status',
      component: TaskList,
      props: (route) => ({ status: route.params.status }),
    },
  ],
});

// Create Vue instance
const app = new Vue({
  vuetify: new Vuetify(),
  router,
  render: (h) => h(TaskList),
});

// Mount Vue instance to #app element
app.$mount('#app');
